import { computed } from "vue";
import { useState, useNuxtApp, navigateTo, createError, defineNuxtRouteMiddleware } from "#app";
import type { AuthUser, AuthRole, AuthScope } from "../src/types";
import "../src/hooks";

// @ts-ignore — virtual module generated by the rampart Nuxt module
import { basePath, forbiddenRoute } from "#build/rampart.config.mjs";

const denyAccess = (roles?: AuthRole[], scopes?: AuthScope[]) => {
  useNuxtApp().callHook("rampart:denied", { roles, scopes });
  if (forbiddenRoute) {
    return navigateTo(forbiddenRoute as string);
  }
  throw createError({ statusCode: 403, message: "Forbidden" });
};

/** Reactive auth state. Hydrates from SSR context on first call. */
export const useAuth = () => {
  const user = useState<AuthUser | null>("rampart:user", () => null);
  const initialized = useState<boolean>("rampart:initialized", () => false);

  // Hydrate from SSR payload on first server render
  if (!initialized.value && import.meta.server) {
    const nuxtApp = useNuxtApp();
    const ssrUser = nuxtApp.ssrContext?.event?.context?.user as AuthUser | undefined;
    if (ssrUser) {
      user.value = ssrUser;
    }
    initialized.value = true;
  }

  const authenticated = computed(() => user.value !== null);

  const login = () => navigateTo(`${basePath}/login`, { external: true });

  const logout = async () => {
    user.value = null;
    await navigateTo(`${basePath}/logout`, { external: true });
  };

  return {
    user,
    authenticated,
    initialized,
    login,
    logout,
  };
};

/** Check if the current user has specific roles. */
export const hasRole = (...roles: AuthRole[]): boolean => {
  const { user } = useAuth();
  if (!user.value) return false;
  const userRoles = (user.value as AuthUser & { roles?: AuthRole[] }).roles;
  if (!userRoles) return false;
  return roles.every((role) => userRoles.includes(role));
};

/** Check if the current user has specific scopes. */
export const hasScope = (...scopes: AuthScope[]): boolean => {
  const { user } = useAuth();
  if (!user.value) return false;
  const userScopes = (user.value as AuthUser & { scopes?: AuthScope[] }).scopes;
  if (!userScopes) return false;
  return scopes.every((scope) => userScopes.includes(scope));
};

/** Creates a route middleware that requires specific roles. */
export const defineRoleMiddleware = (...roles: AuthRole[]) =>
  defineNuxtRouteMiddleware(() => {
    const { authenticated } = useAuth();
    if (!authenticated.value) {
      return navigateTo(`${basePath}/login`, { external: true });
    }
    if (!hasRole(...roles)) {
      return denyAccess(roles);
    }
  });

/** Creates a route middleware that requires specific scopes. */
export const defineScopeMiddleware = (...scopes: AuthScope[]) =>
  defineNuxtRouteMiddleware(() => {
    const { authenticated } = useAuth();
    if (!authenticated.value) {
      return navigateTo(`${basePath}/login`, { external: true });
    }
    if (!hasScope(...scopes)) {
      return denyAccess(undefined, scopes);
    }
  });
